#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int arr[N];
    for (int i = 0; i < N; i++) arr[i] = 0;
    while (Q--) {
        int type, A, B;
        scanf("%d %d %d", &type, &A, &B);
        if (type == 0) {
            for (int i = A; i <= B; i++) arr[i]++;
        } else {
            int count = 0;
            for (int i = A; i <= B; i++) if (arr[i] % 3 == 0) count++;
            printf("%d\n", count);
        }
    }
    return 0;
}

