import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] arr = new int[N];
        while (Q-- > 0) {
            int type = sc.nextInt();
            int A = sc.nextInt();
            int B = sc.nextInt();
            if (type == 0) {
                for (int i = A; i <= B; i++) arr[i]++;
            } else {
                int count = 0;
                for (int i = A; i <= B; i++) if (arr[i] % 3 == 0) count++;
                System.out.println(count);
            }
        }
    }
}

